window.__QUIZ_DATA__=[{"id":"objective>Civic Education>2025>1","subject":"Civic Education","year":"2025","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : GOALS OF CITIZENSHIP EDUCATION","question":"The training of oneself in subjection to self-rules and self-control is achieved as a result of","images":[],"options":{"A":"Integrity","B":"Discipline","C":"Contentment","D":"Commitment"},"answer":"B","explanation":"Discipline refers to the ability to train oneself to follow rules and control impulses. It involves self-regulation and adherence to set standards.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2025>2","subject":"Civic Education","year":"2025","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY","question":"A situation where people are encouraged to define their own values and respect other people's values is known as value","images":[],"options":{"A":"Mobilization","B":"Clarification","C":"Classification","D":"Orientation"},"answer":"B","explanation":"Value clarification is the process through which individuals identify, examine, and develop their own values and learn to respect others'.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>3","subject":"Civic Education","year":"2025","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : WAYS OF PROMOTING NATIONAL CONSCIOUSNESS, INTEGRITY AND UNITY IN THE SOCIETY","question":"A Gambian who wishes to become a Nigerian citizen by naturalisation must be","images":[],"options":{"A":"18 years old and above and have spent at least 15 years in Nigeria","B":"18 years old and above and have spent at least 25 years in Nigeria","C":"21 years and above and have spent at least 10 years in Nigeria","D":"21 years old and above and have spent at least 15 years in Nigeria"},"answer":"D","explanation":"According to the Nigerian Constitution, a person seeking citizenship by naturalisation must be at least 21 years old and must have resided in Nigeria for 15 years continuously.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>4","subject":"Civic Education","year":"2025","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTERPERSONAL RELATIONSHIPS","question":"The major reason for studying Civic Education is that it","images":[],"options":{"A":"Encourages the struggle for political power in the state","B":"Inculcates the spirit of nationalism and patriotism in the citizens of a state","C":"Helps students and citizens to study and understand their physical environment","D":"Enables students and citizens to identify problems in their society without offering functional solutions"},"answer":"B","explanation":"Civic Education develops informed, responsible, and patriotic citizens.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>5","subject":"Civic Education","year":"2025","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : DUTIES AND OBLIGATIONS OF CITIZENS","question":"Which of the following is not a national symbol?","images":[],"options":{"A":"National flag","B":"Voter's card","C":"National currency","D":"Coat of arms"},"answer":"B","explanation":"National symbols are official representations of a country's identity and sovereignty, such as the flag, currency, and coat of arms. A voter's card is an electoral document, not a symbol.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2025>6","subject":"Civic Education","year":"2025","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : FUNCTIONS/NEED FOR CIVIL SOCIETY","question":"The newspapers established by the nationalists helped in","images":[],"options":{"A":"Revealing the weaknesses of the colonial powers","B":"Fighting racial discrimination in the country","C":"Protecting the rights of traditional rulers","D":"Promoting the image of the nationalists"},"answer":"A","explanation":"Nationalist newspapers, like West African Pilot, exposed the injustices and shortcomings of colonial rule, helping to build consciousness among Nigerians.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>7","subject":"Civic Education","year":"2025","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF NATIONALISM","question":"The main significance of nationalism to the development of a country is to","images":[],"options":{"A":"Foster a sense of selflessness towards the nation","B":"Create a sense of allegiance to the nation","C":"Promote the awareness of fundamental human rights","D":"Create a sense of political awareness"},"answer":"B","explanation":"Nationalism promotes loyalty and devotion to one's country, encouraging citizens to act in the national interest, which strengthens unity and development.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>8","subject":"Civic Education","year":"2025","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : IMPORTANCE OF UDHR","question":"How many articles are contained in the Universal Declaration of Human Rights (UDHR) of 1948?","images":[],"options":{"A":"30","B":"33","C":"48","D":"50"},"answer":"A","explanation":"The Universal Declaration of Human Rights (UDHR), adopted in 1948 by the United Nations, contains 30 articles, each outlining fundamental human rights and freedoms.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>9","subject":"Civic Education","year":"2025","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS","question":"A person who is found guilty of an offence and sentenced to prison by a competent court of law would forfeit his/her","images":[],"options":{"A":"Freedom of expression and right to fair hearing","B":"Right to life and right to personal liberty","C":"Right to movement and association","D":"Right to fair hearing and right to movement"},"answer":"C","explanation":"A convicted person loses freedom of movement and association while in prison but retains rights like fair hearing unless legally removed.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>10","subject":"Civic Education","year":"2025","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : IMPORTANCE OF UDHR","question":"A person who writes false statements on social media that harms another person's reputation will be found guilty of","images":[],"options":{"A":"Blackmail","B":"Sedition","C":"Slander","D":"Libel"},"answer":"D","explanation":"Libel is a written or published false statement damaging to a person's reputation. Slander is spoken. Blackmail involves threats, and sedition is inciting resistance against authority.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>11","subject":"Civic Education","year":"2025","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY","question":"The notion that the law should apply to everyone irrespective of their status implies","images":[],"options":{"A":"Supremacy of the law","B":"Fair hearing","C":"Equality before the law","D":"Right to appeal"},"answer":"C","explanation":"This principle ensures that every individual, regardless of class, rank, or status, is subject to the same laws and legal processes. It reinforces fairness and justice in a democratic society.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>12","subject":"Civic Education","year":"2025","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE AND ROLES OF CONSTITUTED AUTHORITY","question":"Constituted authority is necessary in a society because it","images":[],"options":{"A":"Promotes international relations","B":"Ensures security of life and property","C":"Serves as an agent of socialization","D":"Provides scholarship for higher education"},"answer":"B","explanation":"Constituted authorities like the police and government ensure peace, law, and order. Their main purpose is to protect citizens and property, creating a safe environment for development.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>13","subject":"Civic Education","year":"2025","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : WAYS OF PREVENTING CULTISM IN SOCIETY","question":"Responsible parenthood is important to national development because it","images":[],"options":{"A":"Promotes political participation","B":"Ensures upbringing of strict leaders","C":"Emphasizes equality in the society","D":"Helps in reduction of social vices"},"answer":"D","explanation":"Responsible parents instill moral values and discipline, thereby reducing criminality, drug abuse, and other vices among children, which contributes to national progress.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>14","subject":"Civic Education","year":"2025","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFORTS OF GOVERNMENT AND INDIVIDUALS IN STOPPING HUMAN TRAFFICKING","question":"Traffic regulations mean","images":[],"options":{"A":"Rules of traffic jam","B":"Rules guiding pedestrians","C":"Codes and ethics of traffic","D":"Driving on express roads"},"answer":"C","explanation":"Traffic regulations are established rules to guide both motorists and pedestrians for safe and orderly use of roads.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2025>15","subject":"Civic Education","year":"2025","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFORTS OF GOVERNMENT AND INDIVIDUALS IN STOPPING HUMAN TRAFFICKING","question":"Traffic wardens assist in","images":[],"options":{"A":"Presentation of traffic legislation","B":"Mounting of traffic signs","C":"Control of traffic flow","D":"Formulation of rules and regulations"},"answer":"C","explanation":"Traffic wardens are responsible for directing vehicles and pedestrians to avoid congestion and ensure road safety.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2025>16","subject":"Civic Education","year":"2025","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-PERSONAL RELATIONSHIPS","question":"Conflict resolution mechanisms in inter-communal relationships include","images":[],"options":{"A":"Reorientation","B":"Compromise","C":"Commendation","D":"Diligence"},"answer":"B","explanation":"Compromise involves mutual concessions, which is a peaceful approach to resolving disputes between communities.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>17","subject":"Civic Education","year":"2025","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-PERSONAL RELATIONSHIPS","question":"The phrase \"no man is an island\" means that","images":[],"options":{"A":"Mankind needs plants and animals to survive","B":"Citizens cannot operate without help of the government","C":"Individuals need the cooperation of others to progress","D":"Humans are made to marry and have life partners"},"answer":"C","explanation":"The phrase emphasizes interdependence and the need for teamwork in human society.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2025>18","subject":"Civic Education","year":"2025","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : DRUGS THAT CAN BE ABUSED","question":"Which of the following cannot be identified as drug abuse?","images":[],"options":{"A":"Consumption of the right dosage of prescribed drugs","B":"Trafficking of hard substances","C":"Consumption of high dosage of legal drugs","D":"Taking drugs without authorization"},"answer":"A","explanation":"When drugs are taken as prescribed, it is not abuse. Drug abuse involves misuse or illegal use of substances.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>19","subject":"Civic Education","year":"2025","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : MEANING OF HUMAN TRAFFICKING","question":"An aspect of human trafficking involves","images":[],"options":{"A":"Liberation of victims","B":"Counseling of victims","C":"Empowerment of victims","D":"Recruitment of victims"},"answer":"D","explanation":"Trafficking starts with the recruitment and deception of victims for exploitation.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>20","subject":"Civic Education","year":"2025","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFECTS AND CONSEQUENCES OF HUMAN TRAFFICKING","question":"Women are trafficked mainly for","images":[],"options":{"A":"Entrepreneurship","B":"Sexual servitude","C":"Debt bondage","D":"Empowerment"},"answer":"B","explanation":"Many women are trafficked into prostitution, a major form of sexual exploitation.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>21","subject":"Civic Education","year":"2025","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS","question":"Human Immunodeficiency Virus (HIV) mainly leads to","images":[],"options":{"A":"Immune repletion","B":"Immune deficiency","C":"Vines deficiency","D":"Virus repletion"},"answer":"B","explanation":"HIV weakens the immune system, making the body vulnerable to infections and diseases.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>22","subject":"Civic Education","year":"2025","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : MEANING OF DRUG ABUSE","question":"The most common way for babies to contract Human Immunodeficiency Virus (HIV) is through","images":[],"options":{"A":"Blood transfusion","B":"Sharp object sharing","C":"Breastfeeding","D":"Sexual transmission"},"answer":"C","explanation":"An HIV-positive mother can transmit the virus to her baby through breast milk if preventive measures are not taken.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>23","subject":"Civic Education","year":"2025","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : EFFORTS OF GOVERNMENT TOWARDS YOUTH EMPOWERMENT","question":"Youth empowerment can be enhanced through","images":[],"options":{"A":"Imposition of taxes","B":"Political lobbying","C":"Granting of bursaries","D":"Provision of startup capital"},"answer":"D","explanation":"Startup funds help youth initiate businesses, reduce unemployment, and foster independence.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2025>24","subject":"Civic Education","year":"2025","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : EFFORTS OF GOVERNMENT TOWARDS YOUTH EMPOWERMENT","question":"One of the vital skills needed for youth empowerment is","images":[],"options":{"A":"Transversal skills","B":"Cross-curricular skills","C":"Manipulative skills","D":"Non-cognitive skills"},"answer":"A","explanation":"Transversal skills like communication, critical thinking, and adaptability are essential for success in various life contexts.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2025>25","subject":"Civic Education","year":"2025","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : YOUTH EMPOWERMENT SKILLS","question":"Which of the following is not a youth empowerment skill?","images":[],"options":{"A":"Leadership skills","B":"Communication skills","C":"Self-reliance skills","D":"Investigation skills"},"answer":"D","explanation":"Investigation is a research or law enforcement skill, not typically classified as a core empowerment skill.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2025>26","subject":"Civic Education","year":"2025","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT","question":"The power to impeach the president of a country resides in the","images":[],"options":{"A":"Executive","B":"Judiciary","C":"Legislature","D":"Supreme Court"},"answer":"C","explanation":"The legislature has constitutional power to impeach the president after due process.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2025>27","subject":"Civic Education","year":"2025","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : DEFINITION OF LAW AND ORDER","question":"Laws made by both federal and state governments are contained in the","images":[],"options":{"A":"Residual list","B":"Exclusive list","C":"Concurrent list","D":"Joint list"},"answer":"C","explanation":"The concurrent list allows both levels of government to legislate on shared matters like education and health.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>28","subject":"Civic Education","year":"2025","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT","question":"Which of the following government functions is reserved to the exclusive list?","images":[],"options":{"A":"Provision of education","B":"Defence of the nation","C":"Provision of good roads","D":"Establishment of industries"},"answer":"B","explanation":"National defence is the sole responsibility of the federal government and is on the exclusive list.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>29","subject":"Civic Education","year":"2025","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT","question":"What arm of government do ministers, commissioners, and supervisory councillors belong to?","images":[],"options":{"A":"Executive","B":"Legislature","C":"Judiciary","D":"Civil service"},"answer":"A","explanation":"These are political appointees who implement government policies - a key function of the executive arm.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2025>30","subject":"Civic Education","year":"2025","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT","question":"A local government administration supports","images":[],"options":{"A":"Unitary government","B":"Consensus politics","C":"Grassroot government","D":"Foreign culture"},"answer":"C","explanation":"Local governments bring governance closer to the people, especially at the community level.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>31","subject":"Civic Education","year":"2025","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT","question":"The adoption of a federal system of government is necessitated by","images":[],"options":{"A":"Fear of ethnic domination","B":"Inclusion of a secretive clause in the constitution","C":"Availability of abundant natural resources","D":"Adoption of a written constitution"},"answer":"A","explanation":"Nigeria and other multi-ethnic nations adopt federalism to ensure that no ethnic group dominates others and that all regions have autonomy and representation.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>32","subject":"Civic Education","year":"2025","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT","question":"One feature of representative government is","images":[],"options":{"A":"Minority rule","B":"Inter-regional cooperation","C":"Centralization of power","D":"Periodic election"},"answer":"D","explanation":"In representative democracy, citizens elect leaders at regular intervals to make decisions and represent their interests in governance.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>33","subject":"Civic Education","year":"2025","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC","question":"Direct democracy implies that the governance of a country involves","images":[],"options":{"A":"Only male citizens","B":"Only adult male citizens","C":"Citizens' representatives","D":"All the citizens"},"answer":"D","explanation":"In direct democracy, all eligible citizens participate directly in decision-making without intermediaries.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>34","subject":"Civic Education","year":"2025","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : WAYS OF PROMOTING NATIONAL CONSCIOUSNESS, INTEGRITY AND UNITY IN THE SOCIETY","question":"Individual freedom in a democratic country can be enhanced by","images":[],"options":{"A":"One-party system","B":"Multi-party system","C":"Autocratic system","D":"Communal system"},"answer":"B","explanation":"A multi-party system allows for competition, diverse representation, and more choices for citizens, which strengthens democracy and individual freedom.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>35","subject":"Civic Education","year":"2025","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : DEFINITION OF LAW AND ORDER","question":"Absence of one of the following pairs will spell doom for the society.","images":[],"options":{"A":"I and III","B":"IV and V","C":"III and VI","D":"II and VII"},"answer":"D","explanation":"Without law and order and the protection of fundamental human rights, society would collapse into chaos and tyranny.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2025>36","subject":"Civic Education","year":"2025","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : CATEGORIES OF HUMAN RIGHTS","question":"The entitlements of every child in the society are","images":[],"options":{"A":"II and V","B":"V and VII","C":"VI and VII","D":"II and VI"},"answer":"C","explanation":"Children are entitled to proper upbringing (through responsible parenting) and the enjoyment of their rights under the law.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2025>37","subject":"Civic Education","year":"2025","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : GOALS OF CITIZENSHIP EDUCATION","question":"Trade unions, market women associations, and student unions are examples of","images":[],"options":{"A":"Professional associations","B":"Pressure groups","C":"Civil societies","D":"Political parties"},"answer":"C","explanation":"Civil societies are non-governmental groups that advocate for public interests and democratic ideals, including trade unions and student groups.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>38","subject":"Civic Education","year":"2025","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : DEFINITION OF LAW AND ORDER","question":"Inept and irresponsible governance can best be checked by","images":[],"options":{"A":"Criticism of government officials","B":"Attacks on government officials","C":"Revolt against such governments","D":"Recourse to constitutional means"},"answer":"D","explanation":"Citizens should use legal methods like elections, petitions, and judicial redress to address bad governance","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>39","subject":"Civic Education","year":"2025","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT","question":"In order to avoid undue interference in the process of governance, there should be","images":[],"options":{"A":"More roles for traditional rulers","B":"Clear-cut separation of governmental powers","C":"Proper fusion of government functions","D":"Checks and balances"},"answer":"B","explanation":"Separating the powers of the executive, legislature, and judiciary ensures that no arm of government interferes unduly in the duties of another","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>40","subject":"Civic Education","year":"2025","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : LIMITATIONS TO THE EXERCISE OF HUMAN RIGHTS","question":"Which of the following is the implication of immunity clause?","images":[],"options":{"A":"Some public officers cannot be sued","B":"The president can grant pardon to any prisoner/criminal","C":"Public officers are not accountable to the electorate","D":"There is absence of arbitrary rule"},"answer":"A","explanation":"The immunity clause protects certain public officials (e.g. president, governors) from legal prosecution while in office, to allow them perform their duties without distraction.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>41","subject":"Civic Education","year":"2025","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PILLARS OF DEMOCRACY","question":"Neutrality of civil servants implies that they should","images":[],"options":{"A":"Be appointed by a neutral body","B":"Be recruited on the basis of federal character","C":"Have security of tenure","D":"Not be affiliated to any political party"},"answer":"D","explanation":"Civil servants must remain politically neutral to serve all governments faithfully, regardless of party in power.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>42","subject":"Civic Education","year":"2025","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : CONSEQUENCES OF POLITICAL APATHY","question":"The following are forms of political apathy except","images":[],"options":{"A":"Refusal to register for voting","B":"Rigging of elections","C":"Lack of interest","D":"Refusal to give information"},"answer":"B","explanation":"Rigging is electoral malpractice, not political apathy. Political apathy refers to indifference or non-participation in politics.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2025>43","subject":"Civic Education","year":"2025","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT","question":"Use the diagram  to answer the questions below.       What does letter X in the diagram stand for?","images":["data:image/jpeg;base64,"],"options":{"A":"Separation of powers","B":"Checks and balances","C":"Democratic division","D":"Rule of law"},"answer":"A","explanation":"The diagram illustrated the three arms of government. \"X\" represents the principle that each arm functions independently.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>44","subject":"Civic Education","year":"2025","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT","question":"Use the diagram  to answer the questions below.          The letter X as illustrated in the diagram is an integral feature of","images":["data:image/jpeg;base64,"],"options":{"A":"Limited government","B":"Absolute monarchy","C":"Constitutional democracy","D":"Aristocratic government"},"answer":"C","explanation":"Separation of powers is essential in a constitutional democracy to prevent tyranny and promote accountability.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>45","subject":"Civic Education","year":"2025","type":"Objective","topic":"CIVILSOCIETY ORGANISATIONS","question":"Inadequate funding may force Civil Society Organizations (CSOs) to","images":[],"options":{"A":"Lobby for funds from the government","B":"Contest for political power","C":"Scale back activities","D":"Stimulate debate and discussion"},"answer":"C","explanation":"Without adequate funding, CSOs may reduce their operations or shut down, limiting their impact on society.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>46","subject":"Civic Education","year":"2025","type":"Objective","topic":"CIVILSOCIETY ORGANISATIONS","question":"Civil Society Organizations (CSOs) assist government in alleviating poverty by","images":[],"options":{"A":"Influencing government decisions","B":"Promoting youth empowerment","C":"Criticizing malpractice","D":"Exerting influence on legislation"},"answer":"B","explanation":"Many CSOs implement skills acquisition and empowerment programmes targeted at youths and vulnerable populations.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>47","subject":"Civic Education","year":"2025","type":"Objective","topic":"CIVILSOCIETY ORGANISATIONS","question":"Which of the following is a major source of funding for civil societies?","images":[],"options":{"A":"Government allocation","B":"Membership dues","C":"Foreign donations","D":"Taxation and borrowing"},"answer":"C","explanation":"CSOs often rely on international funding from donor agencies to run projects and advocacy.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2025>48","subject":"Civic Education","year":"2025","type":"Objective","topic":"CIVILSOCIETY ORGANISATIONS","question":"Civil Society Organizations (CSOs) are not characterized by","images":[],"options":{"A":"Establishing new political parties","B":"Advocating for benefits of democracy","C":"Checkmating the excesses of government","D":"Acting as training ground for future leaders"},"answer":"A","explanation":"CSOs are non-partisan. They advocate for rights and accountability but do not contest elections or form political parties.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>49","subject":"Civic Education","year":"2025","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE","question":"An established way public servants protest to protect their interests is by","images":[],"options":{"A":"Police action","B":"Hunger strike","C":"Industrial strike","D":"Mass resignation"},"answer":"C","explanation":"When negotiation fails, civil/public servants may resort to strike action as a legal method to demand better working conditions.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2025>50","subject":"Civic Education","year":"2025","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY","question":"Anonymity of civil servants implies that civil servants are","images":[],"options":{"A":"Not expected to take credit or blame in their duty","B":"Expected to abstain from voting during elections","C":"Expected to be fair and impartial in judgment","D":"Not expected to be politically known in the society"},"answer":"A","explanation":"Anonymity means civil servants work behind the scenes. Ministers and politicians take responsibility for government policies, not the civil servants who implement them.","marks":"1","difficulty":"2"}];